import { DocumentBaseView, DocumentView } from "../dtos/document.view";
import { ModelBase } from "./model.base";

export abstract class DocumentModelBase extends ModelBase {
    private _name: string;
    private _modifiedByUserId: string;
    private _modified: Date;

    protected constructor(name: string, modifiedByUserId: string, modifiedAt: Date) {
        super();
        this._name = name;
        this._modifiedByUserId = modifiedByUserId;
        this._modified = modifiedAt;
    }

    protected _getDocumentInfo(): DocumentBaseView {
        return {
            name: this._name,
            modifiedByUserId: this._modifiedByUserId,
            modified: this._modified,
        }
    }

    public abstract getView(): DocumentView;

    public getModifiedByUserId(): string {
        return this._modifiedByUserId;
    }
}