import { DocumentView } from "../model/dtos/document.view";
import { UserView } from "../model/dtos/user.view";
import { ExtensionToIconName, FileExtensionsType } from "../model/enums/file-extensions";
import { FolderModel } from "../model/folder-model";
import { UserService } from "../services/user.service";
import formatTimeAgo from "../utilities/_format-strings";

export default function renderCardList(currentFolder: FolderModel) {
    const userService = new UserService();
    const users = userService.getUsers();
    const userByIdMap = users.reduce((acc, user) => {
        acc.set(user.id, user);
        return acc;
    }, new Map<string, UserView>());

    const documentModelItems = currentFolder.getItems();
    for (const documentModel of documentModelItems) {
        const userView = userByIdMap.get(documentModel.getModifiedByUserId());
        const documentView = documentModel.getView();
        renderCardItem(documentView, userView);
    }
}

function renderCardItem(documentView: DocumentView, userview: UserView) {
    const templateItem = document.getElementById("card-list--template--item") as HTMLTemplateElement;
    const placeholderList = document.getElementById("card-list--placeholder--list");
    const cloned = templateItem.content.cloneNode(true) as HTMLElement;

    const rowIcon = createCardItemIcon(documentView.extension);
    const rowName = createCardItemName(documentView.name, documentView.isSynced);

    cloned.querySelector("table>thead>tr:nth-child(1)>th:nth-child(2)").appendChild(rowIcon);
    cloned.querySelector("table>tbody>tr:nth-child(1)>td:nth-child(2)").appendChild(rowName);
    cloned.querySelector("table>tbody>tr:nth-child(2)>td:nth-child(2)").appendChild(document.createTextNode(formatTimeAgo(documentView.modified)));
    cloned.querySelector("table>tbody>tr:nth-child(3)>td:nth-child(2)").appendChild(document.createTextNode(userview.name));
    placeholderList.appendChild(cloned);
}

function createCardItemIcon(extension?: FileExtensionsType): HTMLSpanElement {
    let iconName;
    if (extension == null) {
        iconName = "folder";
    } else {
        iconName = ExtensionToIconName.get(extension) ?? "excel";
    }
    const spanElement = document.createElement("span");
    spanElement.className = `file-card__icon--${iconName}`;
    return spanElement;
}

function createCardItemName(name: string, hasSyncIcon: boolean): HTMLSpanElement {
    const spanElement = document.createElement("span");
    spanElement.textContent = name;
    if (hasSyncIcon) {
        spanElement.className = `file-card__text-file`;
    }
    return spanElement;
}

