import { DocumentModelBase } from "./abstracts/document-model.base";
import { DocumentView } from "./dtos/document.view";

export class FolderModel extends DocumentModelBase {
    private readonly _items: DocumentModelBase[] = [];

    constructor(name: string, modifiedByUserId: string, modified: Date) {
        super(name, modifiedByUserId, modified);
    }

    public getItems(): DocumentModelBase[] {
        return this._items;
    }

    public addDocument(document: DocumentModelBase): FolderModel {
        this._items.push(document);
        return this;
    }

    public getView(): DocumentView {
        let baseInfo = this._getDocumentInfo();
        return {
            ...baseInfo,
            isSynced: false,
        }
    }
}