import { DocumentView } from "../model/dtos/document.view";
import { UserView } from "../model/dtos/user.view";
import { ExtensionToIconName, FileExtensionsType } from "../model/enums/file-extensions";
import { FolderModel } from "../model/folder-model";
import { UserService } from "../services/user.service";
import formatTimeAgo from "../utilities/_format-strings";

export default function renderTable(currentFolder: FolderModel) {
    const userService = new UserService();
    const users = userService.getUsers();
    const userByIdMap = users.reduce((acc, user) => {
        acc.set(user.id, user);
        return acc;
    }, new Map<string, UserView>());

    const documentModelItems = currentFolder.getItems();
    for (const documentModel of documentModelItems) {
        const userView = userByIdMap.get(documentModel.getModifiedByUserId());
        const documentView = documentModel.getView();
        renderTableRow(documentView, userView);
    }
}

function renderTableRow(documentView: DocumentView, userview: UserView) {
    const templateItem = document.getElementById("documents-table--template--item") as HTMLTemplateElement;
    const placeholderList = document.getElementById("documents-table--placeholder--list");
    const cloned = templateItem.content.cloneNode(true) as HTMLElement;

    const rowIcon = createTableRowIcon(documentView.extension);
    const rowName = createTableRowName(documentView.name, documentView.isSynced);

    cloned.querySelector("tr>td:nth-child(1)").appendChild(rowIcon);
    cloned.querySelector("tr>td:nth-child(2)").appendChild(rowName);
    cloned.querySelector("tr>td:nth-child(3)").appendChild(document.createTextNode(formatTimeAgo(documentView.modified)));
    cloned.querySelector("tr>td:nth-child(4)").appendChild(document.createTextNode(userview.name));

    placeholderList.appendChild(cloned);
}

function createTableRowIcon(extension?: FileExtensionsType): HTMLSpanElement {
    let iconName;
    if (extension == null) {
        iconName = "folder";
    } else {
        iconName = ExtensionToIconName.get(extension) ?? "excel";
    }
    const spanElement = document.createElement("span");
    spanElement.className = `file-table__icon--${iconName}`;
    return spanElement;
}

function createTableRowName(name: string, hasSyncIcon: boolean): HTMLSpanElement {
    const spanElement = document.createElement("span");
    spanElement.textContent = name;
    if (hasSyncIcon) {
        spanElement.className = `file-table__text-file`;
    }
    return spanElement;
}

